SELECT perm.id, perm.user_id, usr.username, usr.real_name, perm.base_id, kb.base_name, perm.can_view, perm.can_upload, perm.can_train_skill, perm.can_analyze, perm.status, perm.grant_time FROM ai_user_knowledge_permission perm INNER JOIN sys_user usr ON usr.id = perm.user_id AND usr.is_deleted = FALSE INNER JOIN ai_knowledge_base kb ON kb.id = perm.base_id AND kb.is_deleted = FALSE WHERE 1 = 1
AND perm.user_id = #{request.userId}
AND perm.base_id = #{request.baseId}
AND perm.status = #{request.status}
ORDER BY perm.grant_time DESC, perm.id DESC

SELECT id, user_id, base_id, can_view, can_upload, can_train_skill, can_analyze,
       status, grant_time, grant_user
FROM ai_user_knowledge_permission
WHERE user_id = #{userId}
  AND base_id = #{baseId}

